{"db_name":"stocktrade_database","query":"SELECT symbol
FROM (
  SELECT 'SPY' AS symbol FROM "SPY" WHERE Date >= '2015-01-01' AND Date <= '2015-12-31' AND "Adj Close" > 200 LIMIT 1
  UNION ALL
  SELECT 'IVV' AS symbol FROM "IVV" WHERE Date >= '2015-01-01' AND Date <= '2015-12-31' AND "Adj Close" > 200 LIMIT 1
) t;"}

{"db_name":"stocktrade_database","query":"SELECT table_name, COUNT(*) AS n_rows
FROM (
  SELECT table_name
  FROM information_schema.tables
  WHERE table_schema='main' AND table_type='BASE TABLE'
) t
JOIN LATERAL (
  SELECT COUNT(*) AS cnt FROM main."SPY"
) x ON TRUE
LIMIT 1;"}
